export const fillMissingDays = (data: any[]) => {
  const days = 7;
  const result: any[] = [];
  for (let i = days - 1; i >= 0; i--) {
    const d = new Date();
    d.setDate(d.getDate() - i);
    const label = d.toLocaleDateString("en-IN", {
      day: "numeric",
      month: "short"
    });
    const found = data.find((x) => x.date === label);
    result.push(
      found || { date: label, total: 0, count: 0 }
    );
  }
  return result;
};