import { formatDate } from "./formatDate";
export const transformSalesData = (invoices: any[]) => {
  if (!invoices || !Array.isArray(invoices)) return [];
  const map = new Map();
  invoices.forEach((inv) => {
    // Sales mein 'invoiceDate' hoti hai, Purchase mein 'purchaseDate' ya 'date'
    const rawDate = inv.invoiceDate || inv.purchaseDate || inv.date;
    if (!rawDate) return; // Agar date hi nahi hai toh skip karo
    const date = formatDate(rawDate);
    const amount = inv.totalAmount || 0;
    if (!map.has(date)) {
      map.set(date, { total: 0, count: 0 });
    }
    const existing = map.get(date);
    existing.total += amount;
    existing.count += 1;
  });
  const result = Array.from(map, ([date, value]) => ({
    date,
    total: value.total,
    count: value.count
  }));
  // Sort by date
  return result.sort(
    (a, b) => new Date(a.date).getTime() - new Date(b.date).getTime()
  );
};