export const getThisMonthRange = () => {
  const today = new Date();
  // Mahine ki pehli tarikh (1st Day of the Month)
  const startDate = new Date(
    today.getFullYear(),
    today.getMonth(),
    1
  );
  // Date ko "YYYY-MM-DD" format mein convert karne ke liye helper
  const format = (date: Date) => {
    // Local date handle karne ke liye padding (taki timezone issue na ho)
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };
  return {
    startDate: format(startDate), // Result: "2026-03-01"
    endDate: format(today)        // Result: "2026-03-15" (agar aaj 15 hai)
  };
};