import { Card, Typography, Box, Tooltip } from "@mui/material";
import { formatNumberShort } from "../../utils/formatNumberShort";

interface KpiCardProps {
  title: string;
  value: number | string;
  isCurrency?: boolean;
  filter: React.ReactNode; // Filter ke liye React node pass karenge
}

const KpiCard: React.FC<KpiCardProps> = ({ title, value, isCurrency, filter }) => {
  const numValue = Number(value) || 0;
  const displayValue = numValue >= 1000000
    ? formatNumberShort(numValue)
    : numValue.toLocaleString('en-IN');
  return (
    <Tooltip title={isCurrency ? `₹${numValue.toLocaleString('en-IN')}` : numValue.toLocaleString()} arrow>
      <Card
        sx={{
          p: 2.4,
          borderRadius: 1,
          height: "100%",
          minHeight: 80, // Sabse bade card (Return/Enquiry) ki height ke barabar set karo
          display: "flex",
          flexDirection: "column",
          justifyContent: "space-between", // Content ko upar-niche stretch karega
          boxShadow: "0px 4px 12px rgba(0,0,0,0.05)",
          cursor: 'pointer'
        }}
      >
        <Box>
          <Box sx={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", mb: 1 }}>
            <Typography sx={{ textTransform: "uppercase", fontSize: "0.75rem", fontWeight: 600, color: "#6C757D" }}>
              {title}
            </Typography>
            {filter && <Box className="swiper-no-swiping">{filter}</Box>}
          </Box>
        </Box>

        <Box sx={{ mt: 'auto' }}> {/* Value ko hamesha niche rakhega alignment ke liye */}
          <Typography sx={{ fontSize: "1.75rem", fontWeight: 800, color: "#212529" ,lineHeight: 1.2}}>
            {isCurrency ? `₹${displayValue}` : displayValue}
          </Typography>
        </Box>
      </Card>
    </Tooltip>
  );
};

export default KpiCard;