import { useCallback, useEffect, useState } from "react";
import { Box, MenuItem, Select } from "@mui/material";
import { Swiper, SwiperSlide } from "swiper/react";
import { FreeMode, Mousewheel, Scrollbar } from "swiper/modules";
import "swiper/css";
import KpiCard from "../KpiCard";
import { getSalesInvoices } from "../../services/salesService";
import { getAllEnquiries } from "../../services/enquiryService";
import EnquiryKpiCard from "../EnquiryKpiCard";
import { getThisMonthRange } from "../../utils/getThisMonthRange";
import { getPreviousMonthEndDate } from "../../utils/getPreviousMonthEndDate";
import { getProductReturns } from "../../services/productReturnService";
import ReturnKpiCard from "../ReturnKpiCard";
import { getPurchaseInvoices } from "../../services/purchaseService";
import { useGstMode } from "../../../../utils/useGstMode";

const KpiSlider = () => {
  const { gstEnabled } = useGstMode();

  const [gstFilterCollect, setGstFilterCollect] = useState("GST"); // To Collect ke liye
  const [gstFilterPay, setGstFilterPay] = useState("GST");         // To Pay ke liye
  const [returnStats, setReturnStats] = useState({
    total: 0,
    created: 0,
    received: 0,
    sent: 0
  });

  const [enquiryStats, setEnquiryStats] = useState({
    total: 0,
    inProgress: 0,
    closed: 0,
    cancelled: 0
  });

  const [kpis, setKpis] = useState([
    { title: "To Collect", value: 0, isCurrency: true },
    { title: "To Pay", value: 0, isCurrency: true },
    { title: "Carry Forward Enquiries", value: 0, },
    // { title: "Pending Orders", value: 9 }
  ]);

  const fetchBorrowing = useCallback(async () => {
    const res = await getSalesInvoices({
      gstType: gstFilterCollect
    });
    const totalBorrowing = res.reduce(
      (sum: number, inv: any) => sum + (inv.balanceAmount || 0), 0
    );
    setKpis(prev => {
      const updated = [...prev];
      updated[0].value = totalBorrowing;
      return updated;
    });
  }, [gstFilterCollect]);

  const fetchEnquiryStats = async () => {
    const { startDate, endDate } = getThisMonthRange();
    const res = await getAllEnquiries({
      startDate,
      endDate
    });

    const data = res.data;
    const stats = {
      total: data.length,
      inProgress: data.filter((e: any) => e.status === "IN_PROGRESS").length,
      closed: data.filter((e: any) => e.status === "CLOSED").length,
      cancelled: data.filter((e: any) => e.status === "CANCELLED").length
    };

    setEnquiryStats(stats);
  };

  // caaryyyforwerd
  const fetchCarryForward = async () => {

    const endDate = getPreviousMonthEndDate();

    const res = await getAllEnquiries({
      status: "IN_PROGRESS",
      endDate
    });

    const carryForward = res.pagination.total;

    setKpis(prev => {
      const updated = [...prev];
      updated[2].value = carryForward;
      return updated;
    });

  };

  const fetchReturnStats = async () => {

    const res = await getProductReturns({});

    const data = res.data;

    const stats = {
      total: res.pagination.total,
      created: data.filter((r: any) => r.status === "RETURN_CREATED").length,
      received: data.filter((r: any) => r.status === "RECEIVED_AT_SHOP").length,
      sent: data.filter((r: any) => r.status === "SENT_TO_VENDOR").length
    };

    setReturnStats(stats);

  };
  const fetchToPay = useCallback(async () => {

    const res = await getPurchaseInvoices({
      gstType: gstFilterPay
    });
    const total = res.reduce(
      (sum: number, inv: any) => sum + (inv.balanceAmount || 0),
      0
    );

    setKpis(prev => {
      const updated = [...prev];
      updated[1].value = total; // 👈 To Pay index
      return updated;
    });

  }, [gstFilterPay]);

  useEffect(() => {
    const fetchAllStats = async () => {
      try {
        // Saari API calls parallel mein shuru hongi
        await Promise.all([
          fetchBorrowing(),
          fetchToPay(),
          fetchEnquiryStats(),
          fetchCarryForward(),
          fetchReturnStats()
        ]);
      } catch (error) {
        console.error("Error fetching KPI stats:", error);
      }
    };

    fetchAllStats();
    // Dependency array mein fetchBorrowing zaroori hai kyunki wo gstFilter pe depend karta hai
  }, [fetchBorrowing, fetchToPay]);

  return (
    <Box sx={{
      width: "100%", mb: 2, "& .swiper-scrollbar": {
        opacity: 0,
        height: "4px",
        transition: "all 0.3s ease"
      },
      "&:hover .swiper-scrollbar": {
        opacity: 1,
        height: "6px"
      }
    }}>
      <Swiper
        modules={[FreeMode, Mousewheel, Scrollbar]} // Modules enable kiye
        spaceBetween={8}
        slidesPerView={4.2}
        freeMode={true} // Isse native swipe feel aayegi (Double finger/trackpad)
        mousewheel={{ forceToAxis: true }} // Mouse scroll se horizontal slide hoga
        scrollbar={{
          draggable: true,
          hide: true, // Scrollbar hamesha dikhegi
          snapOnRelease: true
        }}
        style={{
          display: 'flex',
          alignItems: 'stretch',
          "--swiper-scrollbar-bg-color": "rgba(0,0,0,0.05)",
          "--swiper-scrollbar-drag-bg-color": "#795AB5",
        } as any}

        breakpoints={{
          0: { slidesPerView: 1.3 },
          600: { slidesPerView: 2.2 },
          900: { slidesPerView: 3.2 },
          1200: { slidesPerView: 4.2 }
        }}
      >
        {/* Pehle hum kpis ko map karenge, lekin Enquiry card ko beech mein insert karne ke liye hum use manual index par check karenge */}
        {kpis.map((kpi, index) => {
          // 1. In dono variables ko sahi se define karo
          const isCollect = kpi.title === "To Collect";
          const isPay = kpi.title === "To Pay";
          return (
            // Hum ek array return kar rahe hain jisme slides hain
            // Isse React ko unique keys milengi
            [
              <SwiperSlide key={`kpi-${index}`}>
                <KpiCard title={kpi.title} value={kpi.value} isCurrency={kpi.isCurrency}
                  filter={(isCollect || isPay) && !gstEnabled ? (
                    <Select
                      size="small"
                      // Agar To Collect hai toh collect wali state, nahi toh pay wali
                      value={isCollect ? gstFilterCollect : gstFilterPay}
                      onChange={(e) => {
                        const val = e.target.value;
                        isCollect ? setGstFilterCollect(val) : setGstFilterPay(val);
                      }}
                      variant="standard"
                      disableUnderline
                      sx={{ height: 30, fontSize:'12px' }}
                    >
                      <MenuItem value="ALL" sx={{ height: 30, fontSize:'12px' }}>ALL</MenuItem>
                      <MenuItem value="GST" sx={{ height: 30, fontSize:'12px' }}>GST</MenuItem>
                      <MenuItem value="NON-GST" sx={{ height: 30, fontSize:'12px' }}>NON-GST</MenuItem>
                    </Select>
                  ) : null}

                />
              </SwiperSlide>,
              index === 1 && (
                <SwiperSlide key="enquiry-card" style={{ height: 'auto' }}>
                  <EnquiryKpiCard stats={enquiryStats} />
                </SwiperSlide>
              ),
              index === 2 && (
                <SwiperSlide>
                  <ReturnKpiCard stats={returnStats} />
                </SwiperSlide>
              )
            ]
          );
        })}
      </Swiper>

    </Box>
  );
};

export default KpiSlider;