import SalesChart from "../charts/SalesChart";
import { transformSalesData } from "../../utils/transformSalesData";
import { fillMissingDays } from "../../utils/fillMissingDays";
import { groupByMonth } from "../../utils/groupByMonth";
import { Box, IconButton, Tooltip } from "@mui/material";
import OpenInFullIcon from "@mui/icons-material/OpenInFull";
const ChartCard = ({ invoices, dateRange, setOpenChart }: any) => {
  let processedData;

  if (dateRange === "quarterly") {
    processedData = groupByMonth(invoices);
  }
  else if (dateRange === "this_month" || dateRange === "last_month") {
    processedData = transformSalesData(invoices);
  }
  else if (dateRange === "custom") {
    processedData = transformSalesData(invoices);
  }
  else {
    processedData = fillMissingDays(transformSalesData(invoices));
  }
  return (
    <Box position="relative" height="100%">
      {/* chart */}
      <SalesChart data={processedData} />
      {setOpenChart && (
        <Tooltip title="Expand" arrow placement="top">
          <IconButton
            size="small"
            sx={{
              position: "absolute",
              right: 0,
              bottom: 0
            }}
            onClick={() => setOpenChart(true)}
          >
            <OpenInFullIcon fontSize="small" />
          </IconButton>
        </Tooltip>
      )}
    </Box>
  );
};

export default ChartCard;