import React from "react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer
} from "recharts";
import { formatNumberShort } from "../../../utils/formatNumberShort";
import { Box } from "@mui/material";

type Props = {
  data: any[];
};
const SalesChart: React.FC<Props> = ({ data }) => {
  const minWidthValue =  "100%";
  return (
    <Box sx={{
      overflowX: "auto",
      width: "100%",
      "&::-webkit-scrollbar": { height: "0px" },
      "&::-webkit-scrollbar-thumb": { backgroundColor: "#ccc", borderRadius: "10px" },
      "&::-webkit-scrollbar-track": { backgroundColor: "#f1f1f1" }
    }}>
      <Box sx={{ minWidth: minWidthValue }}>
        <ResponsiveContainer width="100%" height={280}>
          <LineChart
            data={data}
            margin={{
              top: 10,
              right: 30,
              bottom: 40
            }}
          >
            <XAxis
              dataKey="date"
              interval={0}
              angle={-30}
              textAnchor="end"
            />
            <YAxis tickFormatter={formatNumberShort} />
            <Tooltip formatter={(value) => `₹${value}`} />
            <Line
              type="monotone"
              dataKey="total"
              stroke="#1976d2"
              strokeWidth={3}
              dot={{ r: 4 }}
            />
          </LineChart>
        </ResponsiveContainer>
      </Box>
    </Box>
  );
};

export default SalesChart;