
import { Box, Dialog, Grid, MenuItem, Paper, Select, Typography } from "@mui/material";
import ChartCard from "../../ChartCard";
import { getPurchaseInvoices } from "../../../services/purchaseService";
import { useCallback, useEffect, useState } from "react";
import PurchaseLast7DaysTable from "../../tables/PurchaseLast7DaysTable";
import { getThisMonthRange } from "../../../utils/getThisMonthRange";
import { DatePicker } from "@mui/x-date-pickers";
import dayjs from "dayjs";
import { useGstMode } from "../../../../../utils/useGstMode";

const PurchaseOverviewWidget = ({ showTable = true }: { showTable?: boolean }) => {
  const { gstEnabled } = useGstMode();

  const [dateRange, setDateRange] = useState("this_month");
  const [gstType, setGstType] = useState("GST");
  const [invoices, setInvoices] = useState([]);
  const [openChart, setOpenChart] = useState(false)
  const [startDate, setStartDate] = useState<dayjs.Dayjs | null>(null);
  const [endDate, setEndDate] = useState<dayjs.Dayjs | null>(null);

  const fetchPurchases = useCallback(async () => {
    const params: any = { gstType };

    if (dateRange === "custom" && startDate && endDate) {
      params.startDate = startDate.format("YYYY-MM-DD");
      params.endDate = endDate.format("YYYY-MM-DD");
    }

    else if (dateRange === "quarterly") {
      const today = new Date();
      const end = new Date();

      const start = new Date();
      start.setMonth(today.getMonth() - 2);
      start.setDate(1);

      params.startDate = start.toISOString().split("T")[0];
      params.endDate = end.toISOString().split("T")[0];
    }

    else if (dateRange === "this_month") {
      const { startDate, endDate } = getThisMonthRange();
      params.startDate = startDate;
      params.endDate = endDate;
    }

    else {
      params.dateRange = dateRange;
    }

    const data = await getPurchaseInvoices(params);
    setInvoices(data);

  }, [dateRange, gstType, startDate, endDate]);

  useEffect(() => {
    fetchPurchases();
  }, [fetchPurchases]);


  return (
    <Box>
      <Dialog
        open={openChart}
        onClose={() => setOpenChart(false)}
        maxWidth="lg"
        fullWidth
      >
        <Box p={3} height={360}>
          <Typography fontWeight={600} >
            Purchase overview
          </Typography>
          {/* <SalesChart data={processedData} /> */}
          <ChartCard invoices={invoices} dateRange={dateRange} />
        </Box>
      </Dialog>
      <Grid container spacing={1} alignItems="stretch">
        {/* TABLE SIDE */}
        <Grid size={{ xs: 12, md: 4 }} sx={{ display: 'flex' }}>
          <Paper elevation={2} sx={{ p: 3, borderRadius: 1, width: '100%' }}>
            <PurchaseLast7DaysTable />
          </Paper>
        </Grid>
        {/* CHART SIDE */}
        <Grid size={{ xs: 12, md: 8 }} sx={{ display: 'flex' }}>
          <Paper elevation={2} sx={{ p: 3, borderRadius: 1, width: "100%", display: "flex", flexDirection: "column" }}>
            <Box
              display="flex"
              alignItems="center"
              justifyContent="space-between"
              gap={2}
              mb={2}
              sx={{
                borderBottom: "1px solid #eee",
                pb: 1
              }}
            >
              <Typography fontWeight={600}>
                Purchase overview
              </Typography>
              {dateRange === "custom" && (
                <Box sx={{ display: "flex", gap: 2, alignItems: "center" }}>
                  {/* HEADER */}
                  <DatePicker
                    label="Start Date"
                    value={startDate}
                    onChange={(v) => setStartDate(v ? dayjs(v) : null)}
                    slotProps={{ textField: { size: "small", sx: { width: 130 } } }}
                  />
                  <DatePicker
                    label="End Date"
                    value={endDate}
                    onChange={(v) => setEndDate(v ? dayjs(v) : null)}
                    slotProps={{ textField: { size: "small", sx: { width: 130 } } }}
                  />
                </Box>
              )}
              <Box sx={{ display: "flex", gap: 2, alignItems: "center", ml: 'auto' }}>
                <Select
                  size="small"
                  value={dateRange}
                  onChange={(e) => setDateRange(e.target.value)}
                  sx={{ height: 30, fontSize:'12px', borderRadius:1 }}
                >
                  <MenuItem value="this_month" sx={{ height: 30, fontSize:'12px' }}>This Month</MenuItem>
                  <MenuItem value="last_month" sx={{ height: 30, fontSize:'12px' }}>Last Month</MenuItem>
                  <MenuItem value="quarterly" sx={{ height: 30, fontSize:'12px' }}>Quarterly</MenuItem>
                  <MenuItem value="custom" sx={{ height: 30, fontSize:'12px' }}>Custom Date</MenuItem>
                </Select>

                {!gstEnabled && (
                  <Select
                    size="small"
                    value={gstType}
                    onChange={(e) => setGstType(e.target.value)}
                    sx={{ height: 30, fontSize:'12px' }}
                  >
                    <MenuItem value="GST" sx={{ height: 30, fontSize:'12px' }}>GST</MenuItem>
                    <MenuItem value="NON-GST" sx={{ height: 30, fontSize:'12px' }}>Non GST</MenuItem>
                  </Select>
                )}

              </Box>
            </Box>
            <Box sx={{ flexGrow: 1, minHeight: 300 }}>
              <ChartCard invoices={invoices} dateRange={dateRange} setOpenChart={setOpenChart} />
            </Box>
          </Paper>
        </Grid>

      </Grid>
    </Box>
  );
};

export default PurchaseOverviewWidget;