export const formatNumberShort = (num: number): string => {
  if (num === 0 || !num) return "0";
  // Bahut bade numbers ke liye check (Billion)
  if (Math.abs(num) >= 1.0e+9) {
    return (Math.abs(num) / 1.0e+9).toFixed(1).replace(/\.0$/, '') + "B";
  }
  // Million
  if (Math.abs(num) >= 1.0e+6) {
    return (Math.abs(num) / 1.0e+6).toFixed(1).replace(/\.0$/, '') + "M";
  }
  // Thousand
  if (Math.abs(num) >= 1000) {
    return (Math.abs(num) / 1000).toFixed(1).replace(/\.0$/, '') + "K";
  }
  
  return num.toLocaleString('en-IN'); // Chote numbers mein commas lagane ke liye
};