import { Box, Card, Table, TableBody, TableCell, TableHead, TableRow, Typography, Checkbox, Button, CircularProgress } from '@mui/material'
import { useCallback, useEffect, useState } from 'react'
import { request } from '../../../../../utils/request';
import { format } from 'date-fns';
import { toast } from 'react-toastify';

interface Reminder {
    _id: string;
    priority: string;
    description: string;
    reminderDate?: string;
    status?: string;
    date?: string;
    createdAt?: string;
    updatedAt?: string;
}

const RemindersListTable = () => {
    const [reminders, setReminders] = useState<Reminder[]>([]);
    const [selectedReminders, setSelectedReminders] = useState<string[]>([]);
    const [loading, setLoading] = useState(false);
    const [saving, setSaving] = useState(false);

    const formatDateTime = (date: any) => {
        if (!date) return '';
        return format(new Date(date), 'dd/MM/yyyy HH:mm');
    };

    const fetchReminders = useCallback(async () => {
        try {
            setLoading(true);
            const res = await request({
                url: `reminder/get-reminder-by-date`,
                method: 'get'
            })

            if (res.success) {
                setReminders(res.data || []);
                setSelectedReminders([]);
            } else {
                setReminders([]);
            }
        } catch (error: any) {
            console.error(error);
            toast.error(error?.message || 'Failed to fetch reminders');
        } finally {
            setLoading(false);
        }
    }, [])

    useEffect(() => {
        fetchReminders();
    }, [fetchReminders])

    const handleCheckboxChange = (reminderId: string) => {
        setSelectedReminders(prev => {
            if (prev.includes(reminderId)) {
                return prev.filter(id => id !== reminderId);
            } else {
                return [...prev, reminderId];
            }
        });
    };

    const handleSelectAll = () => {
        if (selectedReminders.length === reminders.length) {
            setSelectedReminders([]);
        } else {
            setSelectedReminders(reminders.map(r => r._id));
        }
    };

    const handleSave = async () => {
        if (selectedReminders.length === 0) {
            toast.warning('Please select at least one reminder to update');
            return;
        }

        setSaving(true);
        let successCount = 0;
        let errorCount = 0;

        try {
            for (const reminderId of selectedReminders) {
                try {
                    const response = await request({
                        url: `reminder/update-reminder/${reminderId}`,
                        method: 'put',
                        data: { status: 'CLOSED' }
                    });

                    if (response.success) {
                        successCount++;
                    } else {
                        errorCount++;
                    }
                } catch (error) {
                    errorCount++;
                }
            }

            await fetchReminders();

            if (successCount > 0) {
                toast.success(`${successCount} reminder(s) marked as closed successfully`);
                if (errorCount > 0) {
                    toast.error(`${errorCount} reminder(s) failed to update`);
                }
            } else {
                toast.error('Failed to update reminders');
            }
        } catch (error: any) {
            console.error('Error updating reminders:', error);
            toast.error(error?.message || 'Failed to update reminders');
        } finally {
            setSaving(false);
        }
    };

    const getStatusColor = (status?: string) => {
        switch (status) {
            case 'PENDING': return { color: '#ed6c02', bgcolor: '#fff4e5' };
            case 'CLOSED': return { color: '#2e7d32', bgcolor: '#e8f5e9' };
            default: return { color: '#757575', bgcolor: '#f5f5f5' };
        }
    };

    const getPriorityColor = (priority?: string) => {
        switch (priority) {
            case 'HIGH': return '#d32f2f';
            case 'MEDIUM': return '#ed6c02';
            case 'LOW': return '#2e7d32';
            default: return '#757575';
        }
    };

    return (
        <Card
            sx={{
                p: 1.5, // Reduced padding for dense layout
                borderRadius: 1,
                height: "100%",
                minHeight: 80,
                display: "flex",
                flexDirection: "column",
                justifyContent: "space-between",
                boxShadow: "0px 4px 12px rgba(0,0,0,0.05)",
                cursor: 'pointer'
            }}
        >
            <Box sx={{ width: "100%" }}>
                {/* HEADER with Save Button */}
                <Box
                    display="flex"
                    justifyContent="space-between"
                    alignItems="center"
                    sx={{
                        borderBottom: "1px solid #eee",
                        pb: 0.5, // Reduced padding
                        mb: 1 // Reduced margin
                    }}
                >
                    <Typography fontWeight={600} variant="body2">
                        Reminders
                    </Typography>
                    
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                        {selectedReminders.length > 0 && (
                            <Typography variant="caption" color="text.secondary" sx={{ fontSize: '0.8rem' }}>
                                {selectedReminders.length} selected
                            </Typography>
                        )}
                        <Button
                            variant="contained"
                            size="small"
                            onClick={handleSave}
                            disabled={saving || selectedReminders.length === 0}
                            sx={{
                                textTransform: 'none',
                                fontSize: '0.8rem',
                                py: 0.5,
                                px: 1,
                                minWidth: 'auto'
                            }}
                        >
                            {saving ? <CircularProgress size={14} /> : 'Save'}
                        </Button>
                    </Box>
                </Box>

                {loading ? (
                    <Box sx={{ display: 'flex', justifyContent: 'center', py: 2 }}>
                        <CircularProgress size={20} />
                    </Box>
                ) : (
                    <Table size="small" sx={{ width: '100%', tableLayout: "fixed" }}>
                        <TableHead>
                            <TableRow>
                                <TableCell sx={{ px: 0.5, py: 0.8, width: '5%', fontWeight: 'bold', fontSize: '0.8rem' }}>
                                    <Checkbox
                                        size="small"
                                        checked={reminders.length > 0 && selectedReminders.length === reminders.length}
                                        indeterminate={selectedReminders.length > 0 && selectedReminders.length < reminders.length}
                                        onChange={handleSelectAll}
                                        disabled={reminders.length === 0}
                                        sx={{ p: 0 }}
                                    />
                                </TableCell>
                                <TableCell sx={{ px: 0.5, py: 0.8, width: '15%', fontWeight: 'bold', fontSize: '0.8rem' }}>Reminder Date</TableCell>
                                <TableCell sx={{ px: 0.5, py: 0.8, width: '10%', fontWeight: 'bold', fontSize: '0.8rem' }}>Priority</TableCell>
                                <TableCell sx={{ px: 0.5, py: 0.8, width: '10%', fontWeight: 'bold', fontSize: '0.8rem' }}>Status</TableCell>
                                <TableCell align="left" sx={{ px: 0.5, py: 0.8, fontWeight: 'bold', fontSize: '0.8rem' }}>Description</TableCell>
                            </TableRow>
                        </TableHead>

                        <TableBody>
                            {reminders.length === 0 && (
                                <TableRow>
                                    <TableCell colSpan={5} align="center" sx={{ py: 2 }}>
                                        <Typography variant="body2" color="text.secondary" sx={{ fontSize: '0.8rem' }}>
                                            No reminders found
                                        </Typography>
                                    </TableCell>
                                </TableRow>
                            )}
                            {reminders.map((reminder) => (
                                <TableRow key={reminder._id} hover sx={{ '&:hover': { backgroundColor: '#f5f5f5' } }}>
                                    <TableCell sx={{ px: 0.5, py: 0.5 }}>
                                        <Checkbox
                                            size="small"
                                            checked={selectedReminders.includes(reminder._id)}
                                            onChange={() => handleCheckboxChange(reminder._id)}
                                            disabled={reminder.status === 'CLOSED'}
                                            sx={{ p: 0 }}
                                        />
                                    </TableCell>
                                    <TableCell sx={{ px: 0.5, py: 0.5 }}>
                                        <Typography variant="body2" fontSize="0.8rem">
                                            {formatDateTime(reminder?.reminderDate)}
                                        </Typography>
                                    </TableCell>
                                    <TableCell sx={{ px: 0.5, py: 0.5 }}>
                                        <Typography 
                                            variant="body2" 
                                            fontSize="0.8rem"
                                            sx={{ 
                                                color: getPriorityColor(reminder?.priority),
                                                fontWeight: reminder?.priority === 'HIGH' ? 'bold' : 'normal'
                                            }}
                                        >
                                            {reminder?.priority || 'MEDIUM'}
                                        </Typography>
                                    </TableCell>
                                    <TableCell sx={{ px: 0.5, py: 0.5 }}>
                                        <Box
                                            sx={{
                                                display: 'inline-block',
                                                px: 0.75,
                                                py: 0.5,
                                                borderRadius: 1,
                                                fontSize: '0.65rem',
                                                fontWeight: 500,
                                                backgroundColor: getStatusColor(reminder?.status).bgcolor,
                                                color: getStatusColor(reminder?.status).color,
                                            }}
                                        >
                                            {reminder?.status || 'PENDING'}
                                        </Box>
                                    </TableCell>
                                    <TableCell align="left" sx={{ px: 0.5, py: 0.5 }}>
                                        <Typography 
                                            variant="body2" 
                                            fontSize="0.8rem"
                                            sx={{
                                                whiteSpace: 'nowrap',
                                                overflow: 'hidden',
                                                textOverflow: 'ellipsis'
                                            }}
                                        >
                                            {reminder?.description}
                                        </Typography>
                                    </TableCell>
                                </TableRow>
                            ))}
                        </TableBody>
                    </Table>
                )}
            </Box>
        </Card>
    )
}

export default RemindersListTable;