export const groupByMonth = (invoices: any[]) => {
  const map = new Map();
  // 1. Group by Month-Year (Map use karein)
  invoices.forEach(inv => {
    // invoiceDate standard format (YYYY-MM-DD) mein hona chahiye
    const rawDate = inv.purchaseDate || inv.invoiceDate || inv.date;
    const d = new Date(rawDate);
    const month = d.toLocaleString("en-IN", { month: "short" }); // e.g., "Jan"
    const year = d.getFullYear(); // e.g., 2024
    const key = `${month} ${year}`; // unique key: "Jan 2024"
    const amount = inv.totalAmount || 0;
    if (!map.has(key)) {
      map.set(key, 0);
    }
    map.set(key, map.get(key) + amount);
  });
  // 2. Map ko Array mein convert karein (Abhi tak ye sorted nahi hai)
  const resultArray = Array.from(map, ([date, total]) => ({
    date, // "Jan 2024"
    total
  }));
  // 3. MOST IMPORTANT: Sahi sorting logic apply karein (Date basis par ascending order)
  // Hum Date string parse karke comparsion karenge
  resultArray.sort((a, b) => {
    const dateA = new Date(`1 ${a.date}`); // e.g., new Date("1 Jan 2024")
    const dateB = new Date(`1 ${b.date}`);
    return dateA.getTime() - dateB.getTime(); // Past to Present sort (Ascending)
  });
  return resultArray;
};