import { Card, CardContent, Typography, Grid, Tooltip } from "@mui/material";
import { useNavigate } from "react-router-dom";
import { getThisMonthRange } from "../../utils/getThisMonthRange";
import { formatNumberShort } from "../../utils/formatNumberShort";

type Props = {
  stats: {
    total: number;
    inProgress: number;
    closed: number;
    cancelled: number;
  };
};

const EnquiryKpiCard = ({ stats }: Props) => {
  const navigate = useNavigate();
  const { startDate, endDate } = getThisMonthRange();
  const goToEnquiry = (status?: string) => {
    navigate("/enquiry", {
      state: { status, startDate, endDate, source: "dashboard" }
    });
  };

  return (
    <Card
      sx={{
        borderRadius: 1,
        height: "100%", // Poori height lega
        display: "flex",
        flexDirection: "column",
        boxShadow: "0px 4px 12px rgba(0,0,0,0.05)",
      }}
    >
      <CardContent
        sx={{
          p: 2.4, // Return card ke barabar padding
          display: "flex",
          flexDirection: "column",
          justifyContent: "space-between",
          height: "100%",
          '&:last-child': { pb: 2.4 }
        }}
      >
        <Typography
          variant="subtitle2"
          color="#6C757D"
          fontWeight={600}
          sx={{ textTransform: "uppercase", fontSize: "0.75rem", letterSpacing: "1px", mb: 1 }}
        >
          Enquiries (This Month)
        </Typography>
        <Grid container spacing={0} sx={{ flex: 1, alignItems: "center" }}>
          {[
            { label: "Total", val: stats.total, color: "#212529", status: undefined, big: true },
            { label: "Progress", val: stats.inProgress, color: "#f7cd54", status: "IN_PROGRESS" },
            { label: "Closed", val: stats.closed, color: "#494253", status: "CLOSED" },
            { label: "Cancel", val: stats.cancelled, color: "#DC3545", status: "CANCELLED" },
          ].map((item, idx) => (
            <Grid
              size={{ xs: 3 }}
              key={idx}
              textAlign="center"
              sx={{ cursor: "pointer", overflow: "hidden" }}
              onClick={() => goToEnquiry(item.status)}
            >
              <Tooltip placement="top" title={item.val.toLocaleString()} arrow>
                <Typography
                  variant={item.big ? "h4" : "h6"} // Total ko bada (h4) highlight kiya hai
                  fontWeight={700}
                  color={item.color}
                  noWrap
                  sx={{ fontSize: item.big ? "1.4rem" : "1rem" }}
                >
                  {formatNumberShort(item.val)}
                </Typography>
              </Tooltip>
              <Typography variant="caption" color="#6C757D" sx={{ fontSize: "0.65rem" }}>
                {item.label}
              </Typography>
            </Grid>
          ))}
        </Grid>
      </CardContent>
    </Card>
  );
};

export default EnquiryKpiCard;