import { useCallback, useEffect, useState } from "react";
import {
  Box,
  MenuItem,
  Select,
  Table,
  TableBody,
  TableCell,
  TableFooter,
  TableHead,
  TableRow,
  Tooltip,
  Typography
} from "@mui/material";
import { getSalesInvoices } from "../../../services/salesService";
import { transformSalesData } from "../../../utils/transformSalesData";
import { formatNumberShort } from "../../../utils/formatNumberShort";
import { useGstMode } from "../../../../../utils/useGstMode";

const SalesLast7DaysTable = () => {
  const { gstEnabled } = useGstMode();

  const [rows, setRows] = useState<any[]>([]);
  const [gstType, setGstType] = useState("GST");
  const totalInvoices = rows.reduce((sum, row) => sum + (row.count || 0), 0);
  const totalAmount = rows.reduce((sum, row) => sum + (row.total || 0), 0);
  const fetchLast7Days = useCallback(async () => {
    const today = new Date();

    // 1. API ke liye YYYY-MM-DD format (Start aur End date)
    const formatDateForAPI = (d: Date) => {
      return d.toISOString().split("T")[0]; // API ke liye thik hai
    };
    // 2. Display ke liye format (Jo aapke 'transformed' data se match kare - "9 Mar")
    const formatDateForMatch = (d: Date) => {
      const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
      return `${d.getDate()} ${months[d.getMonth()]}`;
    };
    const start = new Date();
    start.setDate(today.getDate() - 6);
    const data = await getSalesInvoices({
      startDate: formatDateForAPI(start),
      endDate: formatDateForAPI(today),
      gstType
    });
    const transformed = transformSalesData(data);
    // 3. FILL THE GAPS (7 Days Loop)
    const last7Days = [];
    for (let i = 6; i >= 0; i--) {
      const d = new Date();
      d.setDate(today.getDate() - i);

      const displayDate = formatDateForMatch(d); // "15 Mar", "14 Mar" etc.

      // Ab format match hoga!
      const found = transformed.find(item => item.date === displayDate);

      last7Days.push({
        date: displayDate,
        count: found ? found.count : 0,
        total: found ? found.total : 0
      });
    }

    setRows(last7Days);
  }, [gstType]);
  useEffect(() => {
    fetchLast7Days();
  }, [fetchLast7Days]);

  return (
    <Box sx={{ width: "100%" }} >
      {/* HEADER */}
      <Box
        display="flex"
        justifyContent="space-between"
        alignItems="center"

        sx={{
          borderBottom: "1px solid #eee",
          pb: 1,
        }}
        mb={2}
      >
        <Typography fontWeight={600}>
          Last 7 Days Sales
        </Typography>

        {!gstEnabled && (
          <Select
            size="small"
            value={gstType}
            onChange={(e) => setGstType(e.target.value)}
            sx={{ height: 30, fontSize:'12px' }}
          >
            <MenuItem value="GST" sx={{ height: 30, fontSize:'12px' }}>GST</MenuItem>
            <MenuItem value="NON-GST" sx={{ height: 30, fontSize:'12px' }}>Non GST</MenuItem>
          </Select>
        )}

      </Box>

      {/* TABLE */}
      <Table size="small" sx={{ width: '100%', tableLayout: "fixed" }}>

        <TableHead>
          <TableRow>
            <TableCell sx={{ px: 0.5 }}>Date</TableCell>
            <TableCell align="center" sx={{ px: 0.5 }}>Invoices</TableCell>
            <TableCell align="right" sx={{
              px: 0.5,
              fontWeight: 600,
              whiteSpace: "nowrap",
            }}>Total Sales</TableCell>
          </TableRow>
        </TableHead>

        <TableBody>
          {rows.length === 0 && (
            <TableRow>
              <TableCell colSpan={3} align="center">
                No sales found
              </TableCell>
            </TableRow>
          )}
          {rows.map((row) => (
            <TableRow key={row.date}>
              <TableCell sx={{ px: 0.5 }}>{row.date}</TableCell>
              <TableCell align="center" sx={{ px: 0.5 }}>{row.count}</TableCell>
              <TableCell align="right" sx={{ px: 0.5 }}>
                <Tooltip title={`₹${Number(row.total).toLocaleString('en-IN')}`} arrow placement="top">
                  <Typography variant="body2" sx={{ cursor: 'pointer', fontWeight: 500 }}>
                    ₹{formatNumberShort(row.total)}
                  </Typography>
                </Tooltip>
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
        <TableFooter>
          <TableRow sx={{ backgroundColor: '#f9f9f9' }}>
            <TableCell sx={{ fontWeight: 700 }}>Total</TableCell>
            <TableCell align="center" sx={{ fontWeight: 700 }}>{totalInvoices}</TableCell>
            <TableCell align="right" sx={{ fontWeight: 700, color: 'primary.main' }}>
              <Tooltip title={`₹${Number(totalAmount).toLocaleString('en-IN')}`} arrow placement="top">
                <Typography variant="body2" sx={{ fontWeight: 700, cursor: 'pointer' }}>
                  ₹{formatNumberShort(totalAmount)}
                </Typography>
              </Tooltip>
            </TableCell>
          </TableRow>
        </TableFooter>

      </Table>

    </Box>
  );
};

export default SalesLast7DaysTable;